#!/bin/bash
# Deploy a test ERC-721 contract to the local Anvil testnet.
# Prerequisites: `cast` from Foundry (https://book.getfoundry.sh)
# Usage: ./scripts/anvil-deploy-test-nft.sh [RPC_URL]
set -euo pipefail

RPC_URL="${1:-http://localhost:18545}"
# Anvil default account #0 (pre-funded with 10000 ETH)
DEPLOYER="0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266"
DEPLOYER_KEY="0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80"

# Minimal ERC-721 bytecode (compiled from OpenZeppelin ERC721, no constructor args)
# This is a pre-compiled bytecode blob for a simple ERC-721 "TestNFT" with symbol "TNFT"
# Source: OpenZeppelin ERC721.sol compiled with solc 0.8.20, constructor(name="TestNFT", symbol="TNFT")
BYTECODE=""

echo "Deploying TestNFT to Anvil at $RPC_URL..."
echo "Using deployer: $DEPLOYER"

if ! command -v cast &>/dev/null; then
    echo "ERROR: 'cast' not found. Install Foundry:"
    echo "  curl -L https://foundry.paradigm.xyz | bash && foundryup"
    exit 1
fi

# Deploy using cast
CONTRACT_ADDR=$(cast send --rpc-url "$RPC_URL" --private-key "$DEPLOYER_KEY" \
    --create "$BYTECODE" 2>/dev/null | grep "contractAddress" | awk '{print $2}')

if [ -z "$CONTRACT_ADDR" ]; then
    echo "ERROR: Deployment failed"
    exit 1
fi

echo ""
echo "TestNFT deployed at: $CONTRACT_ADDR"
echo ""
echo "To mint an NFT for a wallet:"
echo "  cast send --rpc-url $RPC_URL --private-key \$PRIVATE_KEY $CONTRACT_ADDR 'mint(address)' \$WALLET_ADDRESS"
echo ""
echo "To check balance:"
echo "  cast call --rpc-url $RPC_URL $CONTRACT_ADDR 'balanceOf(address)(uint256)' \$WALLET_ADDRESS"
